const data = $input.first().json;

const CONSULTATION_URL = 'https://calendly.com/metabelly/consultation';

const consultationNote = data.language === 'HR'
  ? `\n\nAko želite razgovarati s nama, slobodno zakažite konzultaciju: ${CONSULTATION_URL}`
  : `\n\nIf you would like to speak with us, feel free to book a consultation: ${CONSULTATION_URL}`;

const isMedical = data.category === 'MEDICAL';
let replyBody = data.auto_reply || '';

if (isMedical) {
  replyBody = data.language === 'HR'
    ? `Hvala vam na povjerenju i što ste nam se obratili.\n\nVaše pitanje zahtijeva savjet stručnjaka, stoga ćemo ga proslijediti timu koji će vam odgovoriti u najkraćem mogućem roku.\n\nZa brži odgovor, možete zakazati konzultaciju: ${CONSULTATION_URL}`
    : `Thank you for reaching out to us.\n\nYour question requires expert advice and we will forward it to our team who will get back to you as soon as possible.\n\nFor a faster response, feel free to book a consultation: ${CONSULTATION_URL}`;
} else if (replyBody) {
  replyBody = replyBody + consultationNote;
}

return [{ json: { ...data, finalReply: replyBody } }];

